def validate_saml_xml_structure(root):
    """
    Performs basic structural validation on the SAML XML.
    Checks for required elements and their namespaces.
    """
    if not root.tag == '{urn:oasis:names:tc:SAML:2.0:protocol}Response':
        logger.error(f"SAML root tag mismatch: {root.tag}")
        return False, "SAML response root tag is not 'Response'."

    status = root.find('samlp:Status', SAML_NS)
    if status is None:
        logger.error("SAML Response missing Status element.")
        return False, "SAML Response missing Status element."

    status_code = status.find('samlp:StatusCode', SAML_NS)
    if status_code is None:
        logger.error("SAML Status missing StatusCode element.")
        return False, "SAML Status missing StatusCode element."

    if status_code.get('Value') != 'urn:oasis:names:tc:SAML:2.0:status:Success':
        status_message = status.find('samlp:StatusMessage', SAML_NS)
        message = status_message.text if status_message is not None else "Unknown SAML status."
        logger.warning(f"SAML Status indicates failure: {status_code.get('Value')}. Message: {message}")
        return False, f"SAML login failed: {message}"

    assertion = root.find('saml:Assertion', SAML_NS)
    if assertion is None:
        logger.error("SAML Response missing Assertion element.")
        return False, "SAML Response missing Assertion element."

    subject = assertion.find('saml:Subject', SAML_NS)
    if subject is None:
        logger.error("SAML Assertion missing Subject element.")
        return False, "SAML Assertion missing Subject element."

    name_id = subject.find('saml:NameID', SAML_NS)
    if name_id is None or not name_id.text:
        logger.error("SAML Subject missing NameID or NameID is empty.")
        return False, "SAML Subject missing NameID."

    attribute_statement = assertion.find('saml:AttributeStatement', SAML_NS)
    if attribute_statement is None:
        logger.warning("SAML Assertion missing AttributeStatement. User attributes might be limited.")
        # Not a critical error for basic auth, but good to log
    
    # You could add more checks here, e.g., for AudienceRestriction, SignedInfo, etc.
    return True, "SAML XML structure is valid."

def parse_saml_assertion(saml_xml):
    """
    Parses the SAML XML response to extract NameID and attributes.
    """
    root = ET.fromstring(saml_xml)

    is_valid, error_message = validate_saml_xml_structure(root)
    if not is_valid:
        raise ValueError(error_message)

    user_data = {}

    # Extract NameID
    name_id_element = root.find(".//saml:NameID", SAML_NS)
    if name_id_element is not None and name_id_element.text:
        user_data['NameID'] = name_id_element.text
    else:
        raise ValueError("NameID not found or is empty in SAML assertion.")

    # Extract Attributes
    attribute_statement = root.find(".//saml:AttributeStatement", SAML_NS)
    if attribute_statement is not None:
        for attribute in attribute_statement.findall('saml:Attribute', SAML_NS):
            name = attribute.get('Name')
            if name:
                attribute_value = attribute.find('saml:AttributeValue', SAML_NS)
                if attribute_value is not None and attribute_value.text:
                    user_data[name] = attribute_value.text.strip()
                elif attribute_value is not None and len(attribute_value.findall('*')) > 0:
                    # Handle complex attributes if needed, for now skip
                    logger.debug(f"Skipping complex SAML attribute '{name}' with multiple children.")
                else:
                    user_data[name] = '' # Store empty string if value is missing but attribute exists
    else:
        logger.warning("No AttributeStatement found in SAML Assertion.")

    return user_data

