@csrf_exempt
def saml_acs(request):
    """
    Assertion Consumer Service (ACS) endpoint.
    Receives SAML POST responses from the Identity Provider.
    """
    if request.method != 'POST':
        return HttpResponse("This endpoint only accepts POST requests.", status=405)

    saml_response_b64 = request.POST.get('SAMLResponse')
    if not saml_response_b64:
        logger.error("SAMLResponse POST parameter is missing.")
        messages.error(request, "SAML authentication failed: Missing SAMLResponse.")
        return HttpResponseRedirect(reverse('home')) # Redirect to a fallback page

    try:
        saml_response_decoded = base64.b64decode(saml_response_b64).decode('utf-8')
        logger.debug(f"Received SAML Response: {saml_response_decoded}")
    except Exception as e:
        logger.error(f"Failed to decode SAMLResponse: {e}")
        messages.error(request, "SAML authentication failed: Invalid SAMLResponse encoding.")
        return HttpResponseRedirect(reverse('home'))

    try:
        user_attributes = parse_saml_assertion(saml_response_decoded)
        logger.info(f"Parsed SAML attributes: {user_attributes}")
    except ValueError as e:
        logger.error(f"SAML XML parsing or validation error: {e}")
        messages.error(request, f"SAML authentication failed: {e}")
        return HttpResponseRedirect(reverse('home'))
    except ET.ParseError as e:
        logger.error(f"SAML XML parsing error (malformed XML): {e}")
        messages.error(request, "SAML authentication failed: Malformed SAML XML response.")
        return HttpResponseRedirect(reverse('home'))
    except Exception as e:
        logger.exception("An unexpected error occurred during SAML parsing.")
        messages.error(request, "SAML authentication failed: An unexpected error occurred.")
        return HttpResponseRedirect(reverse('home'))

    # Authenticate and log in the user
    username = user_attributes.get('NameID')
    if not username:
        logger.error("NameID (username) missing from SAML attributes.")
        messages.error(request, "SAML authentication failed: No username provided.")
        return HttpResponseRedirect(reverse('home'))

    try:
        # Custom authentication backend (see `saml_auth_backend.py` below)
        user = authenticate(request, saml_attributes=user_attributes)

        if user is not None:
            login(request, user)
            logger.info(f"User '{user.username}' successfully logged in via SAML.")
            messages.success(request, f"Welcome, {user.first_name if user.first_name else user.username}!")
            return HttpResponseRedirect(settings.LOGIN_REDIRECT_URL) # e.g., '/dashboard/'
        else:
            logger.warning(f"SAML authentication failed for NameID: {username}. No user object returned by backend.")
            messages.error(request, "SAML authentication failed. User account could not be created or linked.")
            return HttpResponseRedirect(reverse('home'))
    except Exception as e:
        logger.exception(f"Error during Django user authentication/login for NameID: {username}")
        messages.error(request, "SAML authentication failed due to an internal server error.")
        return HttpResponseRedirect(reverse('home'))


