from django.contrib.auth.backends import BaseBackend
from django.contrib.auth.models import User
from django.db import transaction

class SAMLAuthBackend(BaseBackend):
    def authenticate(self, request, saml_attributes=None):
        if saml_attributes is None:
            return None

        username = saml_attributes.get('NameID')
        if not username:
            logger.warning("SAMLAuthBackend: No NameID found in saml_attributes.")
            return None

        # Try to get the user based on the NameID (username)
        try:
            user = User.objects.get(username=username)
        except User.DoesNotExist:
            # If user does not exist, create a new one
            try:
                with transaction.atomic():
                    user = User(username=username)
                    # Set user attributes from SAML_ATTRIBUTE_MAP
                    for saml_attr, django_field in SAML_ATTRIBUTE_MAP.items():
                        if saml_attr in saml_attributes and hasattr(user, django_field):
                            setattr(user, django_field, saml_attributes[saml_attr])
                    
                    user.set_unusable_password() # SAML users don't have passwords in Django
                    user.save()
                    logger.info(f"New Django user '{username}' created from SAML assertion.")
            except Exception as e:
                logger.error(f"Error creating new Django user '{username}' from SAML: {e}")
                return None
        except Exception as e:
            logger.error(f"Error retrieving Django user '{username}': {e}")
            return None
        
        # Update existing user attributes (optional, based on your requirements)
        # This allows IdP to update user info on subsequent logins
        try:
            with transaction.atomic():
                updated = False
                for saml_attr, django_field in SAML_ATTRIBUTE_MAP.items():
                    if saml_attr in saml_attributes and hasattr(user, django_field):
                        current_value = getattr(user, django_field)
                        new_value = saml_attributes[saml_attr]
                        if current_value != new_value:
                            setattr(user, django_field, new_value)
                            updated = True
                if updated:
                    user.save()
                    logger.info(f"Django user '{username}' attributes updated from SAML assertion.")
        except Exception as e:
            logger.error(f"Error updating Django user '{username}' from SAML: {e}")
            # Do not return None, proceed with the existing user even if update failed

        return user

    def get_user(self, user_id):
        try:
            return User.objects.get(pk=user_id)
        except User.DoesNotExist:
            return None

